sealed class Notepad
{
    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Save a research note with a topic heading and body text.")]
    public string SaveNote(
        [Description("Short topic title")] string topic,
        [Description("The note body")] string content)
    {
        _notes.Add((topic, content));
        return $"Note #{_notes.Count} saved: \"{topic}\"";
    }

    [Description("Return all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0) return "No notes saved yet.";
        return string.Join("\n\n", _notes.Select((n, i) =>
            $"── Note {i + 1}: {n.Topic} ──\n{n.Content}"));
    }

    [Description("Search notes for a keyword and return matches.")]
    public string SearchNotes(
        [Description("Keyword to search for")] string keyword)
    {
        var hits = _notes.Where(n =>
            n.Topic.Contains(keyword, StringComparison.OrdinalIgnoreCase) ||
            n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase)).ToList();
        if (hits.Count == 0) return $"No notes match \"{keyword}\".";
        return string.Join("\n\n", hits.Select((n, i) =>
            $"── Match {i + 1}: {n.Topic} ──\n{n.Content}"));
    }
}

