+            $"── Note {i + 1}: {n.Topic} ──\n{n.Content}"));
+    }
+
+    [Description("Search notes for a keyword and return matches.")]
+    public string SearchNotes(
+        [Description("Keyword to search for")] string keyword)
+    {
+        var hits = _notes.Where(n =>
+            n.Topic.Contains(keyword, StringComparison.OrdinalIgnoreCase) ||
+            n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase)).ToList();
+        if (hits.Count == 0) return $"No notes match \"{keyword}\".";
+        return string.Join("\n\n", hits.Select((n, i) =>
+            $"── Match {i + 1}: {n.Topic} ──\n{n.Content}"));
+    }
+}

