4. using Microsoft.Extensions.AI;
5. using OpenAI;
6. 
7. var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
8. var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
9.     ?? throw new InvalidOperationException(
10.         "Set the OPENAI_API_KEY environment variable before running.");
11. 
12. IChatClient chatClient = new OpenAI.Chat.ChatClient(modelName, apiKey)
13.     .AsIChatClient();
14. 
15. var notepad = new Notepad();
16. 
17. var tools = new[]
18. {
19.     AIFunctionFactory.Create(WebSearch.SearchAsync),
20.     AIFunctionFactory.Create(WebSearch.FetchPageAsync),
21.     AIFunctionFactory.Create(notepad.SaveNote),
22.     AIFunctionFactory.Create(notepad.GetAllNotes),
23.     AIFunctionFactory.Create(notepad.SearchNotes),
24. };
25. 
26. Console.Write("Enter a research topic: ");
27. var topic = Console.ReadLine()?.Trim();
28. if (string.IsNullOrEmpty(topic))
29. {
30.     Console.WriteLine("No topic provided. Exiting.");
31.     return;
32. }
33. 
34. Console.WriteLine($"\n🔍 Researching: {topic}\n");
35. 
36. var messages = new List<ChatMessage>
37. {
38.     new(ChatRole.System, """
39.         You are a thorough research agent. Follow these steps:
40.         1. Search the web for the topic using several varied queries.
41.         2. Fetch promising pages to read details.
42.         3. Save every key finding as a note with SaveNote.
43.         4. After 3-5 rounds of searching, call GetAllNotes, then write a
44.            comprehensive, well-structured summary and stop calling tools.
45.         Be methodical and always save findings before summarizing.
46.         """),
47.     new(ChatRole.User,
48.         $"Research the following topic and provide a comprehensive summary:\n{topic}")
49. };
50. 
51. var chatOptions = new ChatOptions { Tools = [.. tools] };
52. 
53. const int maxIterations = 25;
54. for (int i = 0; i < maxIterations; i++)
55. {
56.     var response = await chatClient.GetResponseAsync(messages, chatOptions);
57. 
58.     // Append every message the model produced back into the conversation.
59.     foreach (var msg in response.Messages)
60.         messages.Add(msg);
61. 
62.     var functionCalls = response.Messages
63.         .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
64.         .ToList();
65. 
66.     if (functionCalls.Count == 0)
67.     {
68.         // No tool calls → the agent is finished.
69.         var text = string.Concat(
70.             response.Messages
71.                 .SelectMany(m => m.Contents.OfType<TextContent>())
72.                 .Select(t => t.Text));
73. 
74.         Console.WriteLine("📋 Research Summary:");
75.         Console.WriteLine(new string('═', 60));
76.         Console.WriteLine(text);
77.         Console.WriteLine(new string('═', 60));
78.         break;
79.     }
80. 
81.     // Execute each tool call and feed results back.
82.     foreach (var call in functionCalls)
83.     {
84.         Console.WriteLine($"  🔧 {call.Name}({FormatArgs(call.Arguments)})");
85. 
86.         var tool = tools.FirstOrDefault(t => t.Name == call.Name);
87.         object? result = tool is not null
88.             ? await tool.InvokeAsync(new AIFunctionArguments(call.Arguments!))
89.             : "Unknown tool.";
90. 
91.         var resultStr = result?.ToString() ?? "";
92.         Console.WriteLine($"    ✅ {resultStr.Length} chars returned");
93. 
94.         messages.Add(new ChatMessage(ChatRole.Tool,
95.             [new FunctionResultContent(call.CallId, resultStr)]));
96.     }
97. }
98. 
99. // ── Helpers ──────────────────────────────────────────────────────────────────
100. 
101. static string FormatArgs(IDictionary<string, object?>? args)
102. {
103.     if (args is null || args.Count == 0) return "";
104.     return string.Join(", ", args.Select(kv =>
105.     {
106.         var v = kv.Value?.ToString() ?? "null";
107.         return $"{kv.Key}: \"{(v.Length > 60 ? v[..60] + "…" : v)}\"";
108.     }));
109. }
110. 
111. // ── Web Search Tool ──────────────────────────────────────────────────────────
112. 
113. static partial class WebSearch
114. {
115.     private static readonly HttpClient Http = new();
116. 
117.     [Description("Search the web for a query and return result snippets.")]
118.     public static async Task<string> SearchAsync(
119.         [Description("The search query")] string query)
120.     {
121.         try
122.         {
123.             var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
124.             var req = new HttpRequestMessage(HttpMethod.Get, url);
125.             req.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
126.             var html = await (await Http.SendAsync(req)).Content.ReadAsStringAsync();
127.             var results = ExtractResults(html);
128.             return results.Length > 0
129.                 ? string.Join("\n\n", results.Take(6))
130.                 : "No results found.";
131.         }
132.         catch (Exception ex) { return $"Search failed: {ex.Message}"; }
133.     }
134. 
135.     [Description("Fetch a web page URL and return its text content.")]
136.     public static async Task<string> FetchPageAsync(
137.         [Description("The URL to fetch")] string url)
138.     {
139.         try
140.         {
141.             var req = new HttpRequestMessage(HttpMethod.Get, url);
142.             req.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
143.             var html = await (await Http.SendAsync(req)).Content.ReadAsStringAsync();
144.             var text = StripHtml(html);
145.             return text.Length > 4000 ? text[..4000] + "\n…[truncated]" : text;
146.         }
147.         catch (Exception ex) { return $"Fetch failed: {ex.Message}"; }
148.     }
149. 
150.     private static string[] ExtractResults(string html)
151.     {
152.         var titles = TitleRe().Matches(html);
153.         var snippets = SnippetRe().Matches(html);
154.         var urlMatches = UrlRe().Matches(html);
155.         var list = new List<string>();
156.         for (int i = 0; i < Math.Min(snippets.Count, 6); i++)
157.         {
158.             var title = i < titles.Count ? StripHtml(titles[i].Groups[1].Value) : "Result";
159.             var snippet = StripHtml(snippets[i].Groups[1].Value);
160.             var link = i < urlMatches.Count
161.                 ? WebUtility.UrlDecode(urlMatches[i].Groups[1].Value)
162.                 : "";
163.             list.Add($"[{title}]({link})\n{snippet}");
164.         }
165.         return [.. list];
166.     }
167. 
168.     private static string StripHtml(string html)
169.     {
170.         var t = ScriptRe().Replace(html, " ");
171.         t = StyleRe().Replace(t, " ");
172.         t = TagRe().Replace(t, " ");
173.         t = WebUtility.HtmlDecode(t);
174.         t = WhitespaceRe().Replace(t, " ");
175.         return t.Trim();
176.     }
177. 
178.     [GeneratedRegex(@"<a[^>]*class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline)]
179.     private static partial Regex TitleRe();
180.     [GeneratedRegex(@"<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline)]
181.     private static partial Regex SnippetRe();
