 using System.ComponentModel;
 using System.Net;
 using System.Text.RegularExpressions;
 using Microsoft.Extensions.AI;
 using OpenAI;

 var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 IChatClient chatClient = new OpenAI.Chat.ChatClient(modelName, apiKey)
     .AsIChatClient();

 var notepad = new Notepad();

 var tools = new[]
 {
     AIFunctionFactory.Create(WebSearch.SearchAsync),
     AIFunctionFactory.Create(WebSearch.FetchPageAsync),
     AIFunctionFactory.Create(notepad.SaveNote),
     AIFunctionFactory.Create(notepad.GetAllNotes),
     AIFunctionFactory.Create(notepad.SearchNotes),
 };

 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrEmpty(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 var messages = new List<ChatMessage>
 {
     new(ChatRole.System, """
         You are a thorough research agent. Follow these steps:
         1. Search the web for the topic using several varied queries.
         2. Fetch promising pages to read details.
         3. Save every key finding as a note with SaveNote.
         4. After 3-5 rounds of searching, call GetAllNotes, then write a
            comprehensive, well-structured summary and stop calling tools.
         Be methodical and always save findings before summarizing.
         """),
     new(ChatRole.User,
         $"Research the following topic and provide a comprehensive summary:\n{topic}")
 };

 var chatOptions = new ChatOptions { Tools = [.. tools] };

 const int maxIterations = 25;
 for (int i = 0; i < maxIterations; i++)
 {
     var response = await chatClient.GetResponseAsync(messages, chatOptions);

     // Append every message the model produced back into the conversation.
     foreach (var msg in response.Messages)
         messages.Add(msg);

     var functionCalls = response.Messages
         .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
         .ToList();

     if (functionCalls.Count == 0)
     {
         // No tool calls → the agent is finished.
         var text = string.Concat(
             response.Messages
                 .SelectMany(m => m.Contents.OfType<TextContent>())
                 .Select(t => t.Text));

         Console.WriteLine("📋 Research Summary:");
         Console.WriteLine(new string('═', 60));
         Console.WriteLine(text);
         Console.WriteLine(new string('═', 60));
         break;
     }

     // Execute each tool call and feed results back.
     foreach (var call in functionCalls)
     {
         Console.WriteLine($"  🔧 {call.Name}({FormatArgs(call.Arguments)})");

         var tool = tools.FirstOrDefault(t => t.Name == call.Name);
         object? result = tool is not null
             ? await tool.InvokeAsync(new AIFunctionArguments(call.Arguments!))
             : "Unknown tool.";

         var resultStr = result?.ToString() ?? "";
         Console.WriteLine($"    ✅ {resultStr.Length} chars returned");

         messages.Add(new ChatMessage(ChatRole.Tool,
             [new FunctionResultContent(call.CallId, resultStr)]));
     }
 }

 // ── Helpers ──────────────────────────────────────────────────────────────────

 static string FormatArgs(IDictionary<string, object?>? args)
 {
     if (args is null || args.Count == 0) return "";
     return string.Join(", ", args.Select(kv =>
     {
         var v = kv.Value?.ToString() ?? "null";
         return $"{kv.Key}: \"{(v.Length > 60 ? v[..60] + "…" : v)}\"";
     }));
 }

 // ── Web Search Tool ──────────────────────────────────────────────────────────

 static partial class WebSearch
 {
     private static readonly HttpClient Http = new();

     [Description("Search the web for a query and return result snippets.")]
     public static async Task<string> SearchAsync(
         [Description("The search query")] string query)
     {
         try
         {
             var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
             var req = new HttpRequestMessage(HttpMethod.Get, url);
             req.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
             var html = await (await Http.SendAsync(req)).Content.ReadAsStringAsync();
             var results = ExtractResults(html);
             return results.Length > 0
                 ? string.Join("\n\n", results.Take(6))
                 : "No results found.";
         }
         catch (Exception ex) { return $"Search failed: {ex.Message}"; }
     }

     [Description("Fetch a web page URL and return its text content.")]
     public static async Task<string> FetchPageAsync(
         [Description("The URL to fetch")] string url)
     {
         try
         {
             var req = new HttpRequestMessage(HttpMethod.Get, url);
             req.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
             var html = await (await Http.SendAsync(req)).Content.ReadAsStringAsync();
             var text = StripHtml(html);
             return text.Length > 4000 ? text[..4000] + "\n…[truncated]" : text;
         }
         catch (Exception ex) { return $"Fetch failed: {ex.Message}"; }
     }

     private static string[] ExtractResults(string html)
     {
         var titles = TitleRe().Matches(html);
         var snippets = SnippetRe().Matches(html);
         var urlMatches = UrlRe().Matches(html);
         var list = new List<string>();
         for (int i = 0; i < Math.Min(snippets.Count, 6); i++)
         {
             var title = i < titles.Count ? StripHtml(titles[i].Groups[1].Value) : "Result";
             var snippet = StripHtml(snippets[i].Groups[1].Value);
             var link = i < urlMatches.Count
                 ? WebUtility.UrlDecode(urlMatches[i].Groups[1].Value)
                 : "";
             list.Add($"[{title}]({link})\n{snippet}");
         }
         return [.. list];
     }

     private static string StripHtml(string html)
     {
         var t = ScriptRe().Replace(html, " ");
         t = StyleRe().Replace(t, " ");
         t = TagRe().Replace(t, " ");
         t = WebUtility.HtmlDecode(t);
         t = WhitespaceRe().Replace(t, " ");
         return t.Trim();
     }

     [GeneratedRegex(@"<a[^>]*class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline)]
     private static partial Regex TitleRe();
     [GeneratedRegex(@"<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline)]
     private static partial Regex SnippetRe();
